queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?casting_directors a :Casting_Directors .
    ?casting_directors p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?location_scouts a :Location_Scouts .
    ?location_scouts p:name ?name .
    ?location_scouts p:Salary ?salary_f .
    FILTER((STR(?salary_f) = "80000" || STR(?salary_f) = "80000.0"))
    BIND(?name AS ?o0)
  }
}

